class SummaryRanges {

    private List<Interval> intervals = new ArrayList<>();

    public SummaryRanges() {

    }

    public void addNum(int value) {
        if (intervals.isEmpty() || intervals.get(intervals.size() - 1).end + 1 != value) {
            intervals.add(new Interval(value, value));
        } else {
            intervals.get(intervals.size() - 1).end = value;
        }
    }

    public int[][] getIntervals() {
        int[][] result = new int[intervals.size()][2];
        for (int i = 0; i < intervals.size(); i++) {
            result[i][0] = intervals.get(i).start;
            result[i][1] = intervals.get(i).end;
        }
        return result;
    }
}

class Interval {
    int start;
    int end;
    public Interval(int start, int end) {
        this.start = start;
        this.end = end;
    }
}
